const data = $input.first().json.body;
const orders = data.orders || [];
const deptLoad = data.department_load || {};
const today = data.today;
const basePrompt = data.base_prompt || '';

// Формируем сводку загрузки цехов
let loadSummary = 'ЗАГРУЗКА ЦЕХОВ:\n';
for (const [dept, info] of Object.entries(deptLoad)) {
  loadSummary += `${dept}: ${info.total_hours}ч работы, ${info.workers} рабочих, ${info.hours_per_day}ч/день, нужно ${info.days_needed} дней\n`;
}

// Формируем список заказов
let ordersList = 'ЗАКАЗЫ В ПРОИЗВОДСТВЕ:\n';
for (const o of orders) {
  let line = `[${o.series_id}] ${o.product} | заказ: ${o.order} | проект: ${o.project || 'нет'} | кол-во: ${o.quantity} | срочность: ${o.urgency || 'нет'}`;
  if (o.deadline) {
    line += ` | срок: ${o.deadline} (${o.days_left >= 0 ? o.days_left + ' дн. осталось' : Math.abs(o.days_left) + ' дн. ПРОСРОЧЕНО'})`;
  } else {
    line += ' | срок: не установлен';
  }
  // Прогресс по цехам
  const depts = Object.entries(o.departments || {}).map(([d, s]) => `${d}:${s.ready}/${s.all}`).join(', ');
  if (depts) line += ` | прогресс: ${depts}`;
  // Оставшиеся часы
  const hours = Object.entries(o.remaining_hours || {}).map(([d, h]) => `${d}:${h}ч`).join(', ');
  if (hours) line += ` | осталось работы: ${hours}`;
  if (o.feedback) line += ` | ОБРАТНАЯ СВЯЗЬ: ${o.feedback}`;
  ordersList += line + '\n';
}

const prompt = `${basePrompt}\n\nСегодня: ${today}\n\n${loadSummary}\n${ordersList}\nНа основе данных выше:\n1. Расставь приоритеты всем заказам (sort_weight от 0 до 100, где 100 = максимальный приоритет)\n2. Определи порядок выполнения (sort_position, 1 = первый в очереди)\n3. Дай краткий комментарий по каждому заказу (ai_comment)\n4. Составь ПЛАН НА СЕГОДНЯ — что конкретно делать в каждом цеху\n5. Укажи ПРЕДУПРЕЖДЕНИЯ по заказам которые не успеваем в срок\n\nПри расстановке приоритетов учитывай:\n- Срочность (urgency 1 = горящий, 2 = важный, 3 = обычный)\n- Дни до дедлайна (просроченные = максимальный приоритет)\n- Обратную связь пользователя (feedback)\n- Загрузку цехов\n\nВерни ТОЛЬКО JSON без markdown:\n{\n  "summary": "План на сегодня: ... Предупреждения: ...",\n  "entries": [\n    {"series_id": "ID", "sort_weight": число, "sort_position": число, "ai_comment": "комментарий"}\n  ]\n}`;

return [{ json: { prompt, orders_count: orders.length } }];

const raw = $input.first().json.choices[0].message.content;
let text = raw.trim();
if (text.startsWith('```')) {
  text = text.split('\n').slice(1).join('\n').replace(/```$/, '').trim();
}

try {
  const result = JSON.parse(text);
  return [{ json: result }];
} catch(e) {
  // Попробуем извлечь JSON
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      const result = JSON.parse(match[0]);
      return [{ json: result }];
    } catch(e2) {}
  }
  return [{ json: { summary: 'Ошибка парсинга ответа AI', entries: [], raw: text } }];
}
